import React, { useState } from 'react';
import './footer.css';

const Footer = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    message: '',
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prevData) => ({
      ...prevData,
      [name]: value,
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Ici, vous pouvez ajouter la logique pour traiter le formulaire, comme l'envoi d'un e-mail.
    console.log('Formulaire soumis avec les données suivantes:', formData);
  };

  return (
    <footer id="footer">
      <div className="contact-form">
        <h3>Contactez-moi</h3>
        <form onSubmit={handleSubmit}>
          <label htmlFor="name">Nom :</label>
          <input
            type="text"
            id="name"
            name="name"
            value={formData.name}
            onChange={handleChange}
            required
          />
          <label htmlFor="email">Email :</label>
          <input
            type="email"
            id="email"
            name="email"
            value={formData.email}
            onChange={handleChange}
            required
          />
          <label htmlFor="message">Message :</label>
          <textarea
            id="message"
            name="message"
            value={formData.message}
            onChange={handleChange}
            required
          ></textarea>
          <button type="submit">Envoyer</button>
        </form>
      </div>
      <p>
        Contact Christian Dupont <br />
        26 rue des Allées <br /> 75000 Paris
        <br />
        Tel: 06-01-01-01-01 <br />
        Mail: requindudev@gmail.com
      </p>
      <p>
        Réalisé par Christian Dupont
        <br /> © copyright 2023
      </p>
    </footer>
  );
};

export default Footer;
